diff --git a/llvm/include/llvm/Transforms/IPO/SampleProfileMatcher.h b/llvm/include/llvm/Transforms/IPO/SampleProfileMatcher.h
index c695784641b4e..b3c2cb0e43d5f 100644
--- a/llvm/include/llvm/Transforms/IPO/SampleProfileMatcher.h
+++ b/llvm/include/llvm/Transforms/IPO/SampleProfileMatcher.h
@@ -76,7 +76,7 @@ class SampleProfileMatcher {
   // The new functions found by the call graph matching. The map's key is the
   // the new(renamed) function pointer and the value is old(unused) profile
   // name.
-  std::unordered_map<Function *, FunctionId> FuncToProfileNameMap;
+  std::map<Function *, FunctionId> FuncToProfileNameMap;

   // A map pointer to the FuncNameToProfNameMap in SampleProfileLoader,
   // which maps the function name to the matched profile name. This is used
diff --git a/llvm/include/llvm/Transforms/Utils/SampleProfileLoaderBaseImpl.h b/llvm/include/llvm/Transforms/Utils/SampleProfileLoaderBaseImpl.h
index fc2b13356350d..c8edcd8bee0c5 100644
--- a/llvm/include/llvm/Transforms/Utils/SampleProfileLoaderBaseImpl.h
+++ b/llvm/include/llvm/Transforms/Utils/SampleProfileLoaderBaseImpl.h
@@ -109,7 +109,8 @@ class PseudoProbeManager {
   }

   const PseudoProbeDescriptor *getDesc(StringRef FProfileName) const {
-    return getDesc(Function::getGUIDAssumingExternalLinkage(FProfileName));
+    return getDesc(Function::getGUIDAssumingExternalLinkage(
+        FunctionSamples::getCanonicalFnName(FProfileName)));
   }

   const PseudoProbeDescriptor *getDesc(const Function &F) const {
diff --git a/llvm/lib/Transforms/IPO/SampleProfileMatcher.cpp b/llvm/lib/Transforms/IPO/SampleProfileMatcher.cpp
index b9fb7a3ae4b5b..c55c6e82d56d5 100644
--- a/llvm/lib/Transforms/IPO/SampleProfileMatcher.cpp
+++ b/llvm/lib/Transforms/IPO/SampleProfileMatcher.cpp
@@ -174,7 +174,12 @@ bool SampleProfileMatcher::functionHasProfile(const FunctionId &IRFuncName,
 }

 bool SampleProfileMatcher::isProfileUnused(const FunctionId &ProfileFuncName) {
-  return SymbolMap->find(ProfileFuncName) == SymbolMap->end();
+  // In post-link, the profiled function may have been optimized away from the
+  // module. Check if the function name exists in the pseudo_probe descriptors.
+  return (SymbolMap->find(ProfileFuncName) == SymbolMap->end()) &&
+         (LTOPhase == ThinOrFullLTOPhase::ThinLTOPreLink ||
+          !ProfileFuncName.isStringRef() ||
+          (ProbeManager->getDesc(ProfileFuncName.stringRef()) == nullptr));
 }

 bool SampleProfileMatcher::functionMatchesProfile(
@@ -872,7 +877,12 @@ void SampleProfileMatcher::UpdateWithSalvagedProfiles() {
     // We need to remove the old entry to avoid duplicating the function
     // processing.
     SymbolMap->erase(FuncName);
-    SymbolMap->emplace(I.second, I.first);
+    auto Ret = SymbolMap->emplace(I.second, I.first);
+    LLVM_DEBUG({
+      if (!Ret.second)
+        dbgs() << "Profile Function " << I.second
+               << " has already been matched to another IR function.\n";
+    });
   }

   // With extbinary profile format, initial profile loading only reads profile

