; Function Attrs: nounwind uwtable
declare dso_local void @foo_cold() #0

; Function Attrs: nounwind uwtable
define dso_local i32 @main() #0 !dbg !8 {
entry:
  call void @llvm.pseudoprobe(i64 -2624081020897602054, i64 1, i32 0, i64 -1), !dbg !12
  br i1 false, label %if.then, label %if.end, !dbg !13

if.then:                                          ; preds = %entry
  call void @llvm.pseudoprobe(i64 -2624081020897602054, i64 2, i32 0, i64 -1), !dbg !14
  call void @foo_cold(), !dbg !15
  br label %if.end

if.end:                                           ; preds = %if.then, %entry
  call void @llvm.pseudoprobe(i64 -2624081020897602054, i64 4, i32 0, i64 -1), !dbg !17
  ret i32 0, !dbg !18
}

